import React, { useState } from 'react';
import axios from 'axios';

const RecognizeView: React.FC = () => {
    const [image, setImage] = useState(null);
    const [results, setResults] = useState(null);
    const [loading, setLoading] = useState(false);

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!image) return;

        setLoading(true);
        const formData = new FormData();
        formData.append('image', image);

        try {
            const response = await axios.post('/api/recognize', formData, {
                headers: { 'Content-Type': 'multipart/form-data' }
            });
            setResults(response.data);
        } catch (error) {
            console.error('Recognition failed');
        }
        setLoading(false);
    };

    return (
        <div>
            <form onSubmit={handleSubmit}>
                <input
                    type="file"
                    accept="image/*"
                    onChange={(e) => setImage(e.target.files?.[0] || null)}
                />
                <button type="submit" disabled={loading}>
                    {loading ? 'Recognizing...' : 'Recognize'}
                </button>
            </form>
            {results && (
                <div>
                    <h3>Results:</h3>
                    {results.faces.map((face: any, idx: number) => (
                        <div key={idx}>
                            <p>Face {idx + 1}: {face.matches.length > 0 ? face.matches[0].name : 'Unknown'}</p>
                        </div>
                    ))}
                </div>
            )}
        </div>
    );
};

export default RecognizeView;
